import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import FlightPath from "../components/FlightPath";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [start, setStart] = useState([12.9716, 77.5946]);
  const [end, setEnd] = useState([19.076, 72.8777]);
  const [progress, setProgress] = useState(0);
  const [position, setPosition] = useState(start);

  // Smooth animation
  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((p) => (p >= 1 ? 0 : p + 0.002));
    }, 16);

    return () => clearInterval(interval);
  }, []);

  // Update plane position
  useEffect(() => {
    const lat = start[0] + (end[0] - start[0]) * progress;
    const lng = start[1] + (end[1] - start[1]) * progress;
    setPosition([lat, lng]);
  }, [progress, start, end]);

  // Handle tracking
  const handleTrack = () => {
    if (flightNo === "AI202") {
      setStart([12.9716, 77.5946]); // Bangalore
      setEnd([19.076, 72.8777]);   // Mumbai
    } else if (flightNo === "AI101") {
      setStart([28.6139, 77.209]); // Delhi
      setEnd([19.076, 72.8777]);   // Mumbai
    } else {
      setStart([13.0827, 80.2707]); // Chennai
      setEnd([22.5726, 88.3639]);   // Kolkata
    }

    setProgress(0); // restart animation
  };

  return (
    <div className="dashboard">
      {/* PANEL */}
      <div className="panel">
        ✈️ Flight Tracker

        <input
          type="text"
          value={flightNo}
          onChange={(e) => setFlightNo(e.target.value)}
          placeholder="Enter Flight No"
        />

        <button onClick={handleTrack}>Track</button>

        <p>
          {flightNo ? `Tracking: ${flightNo}` : "Enter a flight number"}
        </p>
      </div>

      {/* MAP */}
      <MapContainer center={position} zoom={5} className="map">
        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} flightNo={flightNo} />
        <FlightPath start={start} end={end} />
      </MapContainer>
    </div>
  );
}
